"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[8408],{4117(e,n,t){t.r(n),t.d(n,{assets:()=>h,contentTitle:()=>o,default:()=>d,frontMatter:()=>a,metadata:()=>r,toc:()=>c});var i=t(4848),s=t(8453);const a={},o="Side Story (Lower): The Truant \u2014 China's Application Revelry and Low-Level Fracture",r={id:"GameVictory/\u5916\u50b3\u4e0b\u7bc7_\u7f3a\u8ab2\u8005_\u4e2d\u570b\u7684\u61c9\u7528\u72c2\u6b61\u8207\u5e95\u5c64\u65b7\u88c2_v1",title:"Side Story (Lower): The Truant \u2014 China's Application Revelry and Low-Level Fracture",description:"1:00 AM, Shanghai. The lights are on in the office of a mobile game studio. The numbers on the screen are ticking upwards\u2014their new gacha game has been online for less than twenty-four hours, and first-day gross revenue has broken 100 million RMB. The product manager pops open a bottle of champagne. The operations director is already calculating the second week's paid conversion rate. The art team is rushing to produce the character illustrations for the next limited banner. The entire company is like a precision money-printing machine, every gear spinning at breakneck speed.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u5916\u50b3\u4e0b\u7bc7_\u7f3a\u8ab2\u8005_\u4e2d\u570b\u7684\u61c9\u7528\u72c2\u6b61\u8207\u5e95\u5c64\u65b7\u88c2_v1.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u5916\u50b3\u4e0b\u7bc7_\u7f3a\u8ab2\u8005_\u4e2d\u570b\u7684\u61c9\u7528\u72c2\u6b61\u8207\u5e95\u5c64\u65b7\u88c2_v1",permalink:"/MythogenEngine/en/docs/GameVictory/\u5916\u50b3\u4e0b\u7bc7_\u7f3a\u8ab2\u8005_\u4e2d\u570b\u7684\u61c9\u7528\u72c2\u6b61\u8207\u5e95\u5c64\u65b7\u88c2_v1",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Side Story (Upper): The Prison Breaker \u2014 Google's Soulless Gamble and the TPU Closed Loop",permalink:"/MythogenEngine/en/docs/GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1"},next:{title:"Sci-Fi Vibe",permalink:"/MythogenEngine/en/docs/category/sci-fi-vibe"}},h={},c=[{value:"I. The Zenith of the Spreadsheet Soul",id:"i-the-zenith-of-the-spreadsheet-soul",level:2},{value:"II. The Fracture",id:"ii-the-fracture",level:2},{value:"III. The Chinese Version of the Software Prison",id:"iii-the-chinese-version-of-the-software-prison",level:2},{value:"IV. The Bill for Skipping Class",id:"iv-the-bill-for-skipping-class",level:2},{value:"V. Settlement",id:"v-settlement",level:2}];function l(e){const n={code:"code",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"side-story-lower-the-truant--chinas-application-revelry-and-low-level-fracture",children:"Side Story (Lower): The Truant \u2014 China's Application Revelry and Low-Level Fracture"})}),"\n",(0,i.jsx)(n.p,{children:"1:00 AM, Shanghai. The lights are on in the office of a mobile game studio. The numbers on the screen are ticking upwards\u2014their new gacha game has been online for less than twenty-four hours, and first-day gross revenue has broken 100 million RMB. The product manager pops open a bottle of champagne. The operations director is already calculating the second week's paid conversion rate. The art team is rushing to produce the character illustrations for the next limited banner. The entire company is like a precision money-printing machine, every gear spinning at breakneck speed."}),"\n",(0,i.jsx)(n.p,{children:"In the same time zone, Shenzhen. Inside an R&D building at Huawei, several engineers stare at red error messages on a terminal, their expressions grave. They are trying to get a server equipped with a domestic Ascend 910B AI chip to run the latest version of an open-source large language model from GitHub. The model's code is written in PyTorch. PyTorch calls CUDA underneath. Their chip is not from NVIDIA."}),"\n",(0,i.jsx)(n.p,{children:"Error messages, line after line."}),"\n",(0,i.jsx)(n.p,{children:"The most profitable applications and the most powerless foundation coexist within the same nation. This is not an accident. This is the settlement of a complete chain of causality stretching back thirty years."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"i-the-zenith-of-the-spreadsheet-soul",children:"I. The Zenith of the Spreadsheet Soul"}),"\n",(0,i.jsx)(n.p,{children:"If Google in the previous side story was the prototype of the spreadsheet soul, then China's internet giants are its ultimate form."}),"\n",(0,i.jsx)(n.p,{children:"Tencent, NetEase, ByteDance\u2014these three companies combined control a massive chunk of the global mobile gaming market. They did not win by making the best games. They won by making the most precise monetization machines."}),"\n",(0,i.jsx)(n.p,{children:'The pity timers in gacha mechanics, the psychological pressure of event countdowns, the social comparison driven by rankings, the anchoring effect of first-time top-up bundles\u2014the people standing behind these things are not game designers, but behavioral psychologists and data scientists. The exact moment a pop-up appears, the magnitude of a limited-time discount, the color and size of the "Draw Again" button\u2014every detail is precisely calibrated through A/B testing.'}),"\n",(0,i.jsx)(n.p,{children:"The results are astounding. A successful Chinese mobile game can generate over 100 million RMB in revenue on its first day online\u2014a figure that exceeds the first-week global sales of products polished for three to five years by hundreds of people at many Western AAA game studios."}),"\n",(0,i.jsx)(n.p,{children:"But what these companies do has a fundamental difference from the builders of tech hegemony described in every chapter of the main text."}),"\n",(0,i.jsx)(n.p,{children:"Microsoft used DirectX to unify the PC gaming graphics interface\u2014this drove the evolution of GPU hardware. NVIDIA used CUDA to stuff general-purpose compute cores into gaming graphics cards\u2014this birthed the entire AI computing industry. TSMC honed extreme yields on the massive silicon of gaming GPUs\u2014this paved the way for the mass production of AI chips. Every player in the main text, no matter how selfish their motives or how dirty their methods, at least objectively pushed some form of low-level technological progress."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"China's gaming giants have not pushed any low-level technology."})}),"\n",(0,i.jsx)(n.p,{children:"Their games run on chips designed by others (Qualcomm's Snapdragon, Apple's A-series), fabricated in factories built by others (TSMC, Samsung), built using engines developed by others (Unity, Unreal), and operate on operating systems established by others (Android, iOS). From chip to engine to OS, not a single link in the entire technology supply chain is China's own."}),"\n",(0,i.jsx)(n.p,{children:"This is not because Chinese engineers aren't smart enough. It's because making money was too easy."}),"\n",(0,i.jsx)(n.p,{children:"When you can use thirty people, spend six months, make a reskinned gacha game, and break 100 million in first-month revenue\u2014why would you use three hundred people, invest ten years, and build a low-level framework with no immediate return? When venture capital money floods like water into bike-sharing, community group buying, and short-video platforms\u2014why would capital be invested in semiconductor R&D, where the return cycle is ten years and the success rate is abysmal?"}),"\n",(0,i.jsx)(n.p,{children:"In the NVIDIA story told in Chapter 7, Jensen Huang started stuffing CUDA cores into GeForces in 2006. He waited a full six years before AlexNet found a use for CUDA. For six years, that R&D investment looked like pure waste on a financial statement."}),"\n",(0,i.jsx)(n.p,{children:"China's capital markets do not allow six years of waste. China's internet companies do not allow foundational investments that show no return for ten years. Their systems\u2014quarterly reviews, KPI-driven goals, investor pressure after going public\u2014are, like Google's OKR system, structurally incompatible with long-term, low-level R&D."}),"\n",(0,i.jsx)(n.p,{children:"So China did one thing: it built a skyscraper piercing the clouds on someone else's foundation."}),"\n",(0,i.jsx)(n.p,{children:"The skyscraper is full of the world's most generous mobile gamers. Every floor of the skyscraper is equipped with the world's most precise paid conversion engines. From the outside, the skyscraper is magnificent."}),"\n",(0,i.jsx)(n.p,{children:"But the foundation isn't its own."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"ii-the-fracture",children:"II. The Fracture"}),"\n",(0,i.jsx)(n.p,{children:"In October 2022, the US Department of Commerce issued new export control regulations. Simply put: prohibiting the sale of advanced AI chips and semiconductor manufacturing equipment to China. NVIDIA's A100 and H100 could no longer be sold. ASML's EUV (Extreme Ultraviolet) lithography machines could no longer be sold. TSMC and Samsung could no longer fabricate advanced-process AI chips for Chinese clients."}),"\n",(0,i.jsx)(n.p,{children:"Overnight, the foundation cracked."}),"\n",(0,i.jsx)(n.p,{children:"But the degree of the cracking was not uniform. Some places cracked shallowly, while others cracked all the way to the root."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Where it cracked shallowly: Mature Processes."})}),"\n",(0,i.jsx)(n.p,{children:"The chips needed for electric vehicles, home appliances, and industrial controllers mostly remain on 28nm or older processes. These processes do not require EUV lithography machines\u2014they can be made with traditional DUV (Deep Ultraviolet) light. SMIC (Semiconductor Manufacturing International Corporation) frantically expanded production in this sector, using state subsidies to suppress prices and dumping them on the global market. A 28nm chip is not advanced, but it is the blood of modern industry\u2014there's one inside every air conditioner, every electric vehicle, every router."}),"\n",(0,i.jsx)(n.p,{children:"On this front, China achieved self-sufficiency. Not the best, but good enough."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Where it cracked to the root: Advanced Processes."})}),"\n",(0,i.jsx)(n.p,{children:"In August 2023, Huawei released the Mate 60 Pro without any warning. After tearing it down, semiconductor analysts worldwide gasped: the Kirin 9000S chip inside was manufactured by SMIC using a 7nm-class process."}),"\n",(0,i.jsx)(n.p,{children:"Under the condition of being banned from using EUV lithography machines."}),"\n",(0,i.jsx)(n.p,{children:"The method SMIC used is called multiple patterning\u2014splitting a single layer of circuitry into multiple exposures, repeatedly stacking them using lower-precision DUV machines, ultimately achieving a result close to 7nm. This is a brute-force crack. It works. But the cost is immense."}),"\n",(0,i.jsx)(n.p,{children:"There is a core concept in Chapter 8: TSMC's advanced processes are nurtured \"by going with the flow.\" Apple's initial launch validation, gaming GPUs' stress testing, console SoCs' long-term orders\u2014each client brings different technical demands, pushing TSMC to push yields to the limit step by step in actual combat. The reason TSMC's 7nm yield could reach the level of commercial mass production is that it had been honed countless times across dozens of clients and hundreds of chip designs."}),"\n",(0,i.jsx)(n.p,{children:"SMIC does not have these clients. Its advanced process orders come almost entirely from one company: Huawei. It has no small-die high-yield validation from Apple, no massive-die extreme stress testing from NVIDIA, no long-term stable console orders from Sony and Microsoft. It is brute-forcing yields upward while under blockade, using state subsidies, with extreme client homogeneity."}),"\n",(0,i.jsx)(n.p,{children:"The result: The Kirin 9000S can ship, but yields are extremely low and costs are extremely high. The number of passing chips cut from a single wafer is far below the level of TSMC's equivalent process. The true cost of every Kirin 9000S\u2014including the loss of defective units\u2014might be several times that of TSMC's equivalent chip."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"This is not a victory of the market. This is a battle for survival, using state subsidies to fill the thirty-year gap of skipping hardware classes."})}),"\n",(0,i.jsx)(n.p,{children:"Furthermore, even if Huawei managed to fabricate the chip, the story isn't over. Because there is an even deeper wall."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iii-the-chinese-version-of-the-software-prison",children:"III. The Chinese Version of the Software Prison"}),"\n",(0,i.jsx)(n.p,{children:"The Kirin 9000S is a smartphone chip. A smartphone chip's software ecosystem is relatively simple\u2014Android OS, applications, drivers\u2014Huawei can rely on its own HarmonyOS to bypass Google's software blockade. Difficult, but feasible."}),"\n",(0,i.jsx)(n.p,{children:"AI chips are another matter entirely."}),"\n",(0,i.jsx)(n.p,{children:"Huawei's Ascend 910B is an AI training chip. On pure hardware specs, Huawei claims that in certain specific training tasks, its performance can approach or even exceed NVIDIA's A100 by about 20%. The subsequent 910C and 910D take aim straight at NVIDIA's H100."}),"\n",(0,i.jsx)(n.p,{children:'But between "approaching in hardware compute" and "can be used as a replacement," there is an invisible abyss.'}),"\n",(0,i.jsx)(n.p,{children:"The name of that abyss is CUDA."}),"\n",(0,i.jsx)(n.p,{children:"Chapter 7 discussed CUDA's four-layer lock. Now let's apply China's situation:"}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Layer One \u2014 Hardware Instruction Set:"})," The Ascend chips use Huawei's own Da Vinci architecture, completely different from NVIDIA's PTX/SASS. This means all code compiled for NVIDIA GPUs cannot run on Ascend. It must be recompiled."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Layer Two \u2014 Compute Libraries:"})," NVIDIA has cuDNN, cuBLAS, NCCL\u2014each one the result of hundreds-strong teams spending ten years deeply optimizing for NVIDIA hardware. Huawei's equivalent is CANN (Compute Architecture for Neural Networks). CANN's feature coverage and performance maturity are more than a generation behind CUDA's libraries."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Layer Three \u2014 Framework Binding:"})," AI researchers worldwide write code in PyTorch. PyTorch calls CUDA by default under the hood. Huawei developed its own AI framework, MindSpore, and also built an adaptation layer to allow PyTorch to run on Ascend. But compatibility issues with the adaptation layer pop up endlessly\u2014the red error messages faced by those Shenzhen engineers at the beginning of this chapter are problems originating from this layer. Hidden inside the code of every open-source model are dozens of implicit CUDA dependencies. On the surface, you just change one line to ",(0,i.jsx)(n.code,{children:"device = 'npu'"}),", but in reality, the underlying library calls, memory management, and compute precision handling are fraught with traps."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Layer Four \u2014 Knowledge Binding:"})," China's AI engineers learned CUDA in university. The textbooks they read use CUDA for examples. The Stack Overflow pages they search use CUDA to answer questions. Every open-source project they fork on GitHub runs on NVIDIA GPUs by default. Asking them to switch to Huawei's CANN and MindSpore is akin to asking them to forget the language they know and learn a completely new one from scratch."]}),"\n",(0,i.jsx)(n.p,{children:'The concluding sentence of Chapter 7 in the main text is: "CUDA is not an API. CUDA is a prison. And you have lived inside it since the day you enrolled in school."'}),"\n",(0,i.jsxs)(n.p,{children:["China's AI engineers face the exact same prison. The difference is: NVIDIA's ecosystem grew naturally over twenty years through the work of tens of millions of gamers and developers worldwide. ",(0,i.jsx)(n.strong,{children:"The alternative ecosystem China is trying to build is being brute-forced by administrative directives under the desperate straits of sanctions."})]}),"\n",(0,i.jsx)(n.p,{children:"The difference between these two ecosystems is not a difference of quantity. It is a difference of quality."}),"\n",(0,i.jsx)(n.p,{children:"A naturally grown ecosystem has roots\u2014every one of its nodes is actively chosen by someone. Someone published a paper using CUDA, someone built a product using CUDA, someone founded a company on CUDA. Cut off any single node, and the other nodes remain."}),"\n",(0,i.jsx)(n.p,{children:"An ecosystem built by administrative directives has no roots\u2014every one of its nodes is mandated. The moment the directives loosen, the moment subsidies decrease, the moment NVIDIA finds a way to bypass sanctions (such as releasing the nerfed H20 chip specifically for the Chinese market), developers will run back to CUDA's embrace overnight."}),"\n",(0,i.jsx)(n.p,{children:"In fact, this is already happening. In 2024, when NVIDIA lowered the price of the H20 to roughly the same level as the Ascend 910B, many Chinese AI companies resumed purchasing NVIDIA chips. Not because they don't support domestic products\u2014but because code written in CUDA doesn't need to be changed, while code written in CANN has to be rewritten."}),"\n",(0,i.jsx)(n.p,{children:"Engineers are rational. The rational choice is always the path of least resistance. And CUDA is the path of least resistance."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iv-the-bill-for-skipping-class",children:"IV. The Bill for Skipping Class"}),"\n",(0,i.jsx)(n.p,{children:"Now we can string the causal chain together."}),"\n",(0,i.jsxs)(n.p,{children:["The core argument of the main text is: ",(0,i.jsx)(n.strong,{children:"The money and demands of gamers inadvertently nourished the foundational infrastructure of the entire tech hegemony."})," From DirectX to CUDA to TSMC's advanced processes\u2014every brick has the fingerprints of gaming on it."]}),"\n",(0,i.jsx)(n.p,{children:"China's negative example perfectly validates this argument."}),"\n",(0,i.jsx)(n.p,{children:"China has the most profitable game companies in the world. But not a single cent of the money these companies made flowed to foundational technology. Their games run on imported chips, are made with imported engines, and are sold in imported operating systems. They only did one thing: set up on a stage built by someone else, using the most precise psychological tools to pick the pockets of players."}),"\n",(0,i.jsx)(n.p,{children:'When America said, "You can no longer use this stage," China suddenly realized: Beneath its skyscraper in the application layer, it had no foundation.'}),"\n",(0,i.jsx)(n.p,{children:"This wasn't caused by sanctions. Sanctions only caused the bill for skipping class to arrive early."}),"\n",(0,i.jsx)(n.p,{children:"The real cause is hidden thirty years ago. When Jensen Huang decided to found NVIDIA in a Denny's diner, Chinese capital was pouring into real estate. When Morris Chang was building TSMC's first factory in Hsinchu, China's manufacturing sector was doing OEM assembly. When CUDA was born in 2006 and university students worldwide started writing parallel computing programs on NVIDIA graphics cards, China's smartest graduates were going to Tencent and Alibaba\u2014to make social software, e-commerce platforms, and mobile games."}),"\n",(0,i.jsx)(n.p,{children:"Every step was rational. The spreadsheets for every step looked fantastic."}),"\n",(0,i.jsx)(n.p,{children:"But every step skipped the exact same thing: the foundation."}),"\n",(0,i.jsx)(n.p,{children:"The foundation of hardware\u2014the ability to independently design high-performance chips. The foundation of software\u2014the ability to independently build developer ecosystems. The foundation of manufacturing\u2014the ability to produce advanced process chips without foreign equipment."}),"\n",(0,i.jsx)(n.p,{children:"These three \"foundations\"\u2014the main text of this book spent three chapters explaining how they were built: Chapter 7 (CUDA's software ecosystem), Chapter 8 (TSMC's manufacturing capability), and Chapter 4 (NVIDIA's accumulation of hardware design from the brink of death to its rise). Building each of these foundations took at least fifteen years. In the process of building each foundation, gaming played a critical role\u2014not as an end, but as a stress test arena and a funding pool."}),"\n",(0,i.jsx)(n.p,{children:"China skipped this process. It started directly from the application layer. Using the shortest time, the highest efficiency, and the most precise monetization designs, it built the world's most profitable digital entertainment empire."}),"\n",(0,i.jsx)(n.p,{children:"And then discovered the empire's foundation belonged to someone else."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"v-settlement",children:"V. Settlement"}),"\n",(0,i.jsx)(n.p,{children:"There is a question worth asking: Can China catch up on its missed classes?"}),"\n",(0,i.jsx)(n.p,{children:"The answer is: Technically, yes, but chronologically, there might not be enough time."}),"\n",(0,i.jsx)(n.p,{children:"Huawei's Ascend chips are generation-by-generation approaching NVIDIA in hardware compute. SMIC has achieved self-sufficiency in mature processes and brute-forced its way to 7nm-class advanced processes. Baidu's Kunlun chips and Alibaba's Hanguang chips are all attempting to build alternatives to varying degrees."}),"\n",(0,i.jsxs)(n.p,{children:["But Chapter 8 of the main text stated a cruel truth: ",(0,i.jsx)(n.strong,{children:"The reason you can't catch up isn't the technological gap; it's the trust gap."})," TSMC's moat isn't any single technology\u2014it is thirty years of accumulated trust from the global fabless ecosystem. You cannot catch up with a slide deck. You cannot catch up in a single quarter."]}),"\n",(0,i.jsx)(n.p,{children:"The same logic applies to the software ecosystem. CUDA's moat isn't the performance of cuDNN\u2014it is every university in the world, every GitHub project, every textbook, and the muscle memory in the brain of every AI engineer. You cannot catch up with administrative directives. You cannot catch up with subsidies. You can only catch up with time\u2014and during the ten years you spend chasing, NVIDIA is not standing still either."}),"\n",(0,i.jsx)(n.p,{children:"China faces a dual catch-up problem. On the hardware end, it is chasing TSMC\u2014a company that invests over thirty billion dollars in capital expenditures annually and has thirty years of accumulated process experience. On the software end, it is chasing CUDA\u2014an ecosystem naturally grown by tens of millions of developers globally."}),"\n",(0,i.jsx)(n.p,{children:"Both chases must happen simultaneously. Both targets are moving. And the pursuer is being choked at the most critical supply chains\u2014it cannot buy advanced lithography equipment, it cannot buy the newest NVIDIA chips, it cannot use the most advanced process foundry services."}),"\n",(0,i.jsx)(n.p,{children:"This is the price of skipping class."}),"\n",(0,i.jsx)(n.p,{children:"You can copy a highly profitable mobile game in a few months. You can use state capital to brute-force a spike in chip production capacity for a certain process node within three years. But you cannot use money or administrative orders to buy overnight a foundational ecosystem jointly woven by tens of millions of engineers and developers over twenty years."}),"\n",(0,i.jsxs)(n.p,{children:["The core pattern of the main text is: ",(0,i.jsx)(n.strong,{children:"Convenience attracts users \u2192 Lock-in bounds developers \u2192 Monopoly collects rent. The cost only materializes twenty or thirty years later."})]}),"\n",(0,i.jsxs)(n.p,{children:["China's case is the mirror image of this pattern: ",(0,i.jsx)(n.strong,{children:"However much hard work you skipped in building your foundation back then, history will demand you spit it back out with interest."})," The cost, similarly, only arrives twenty or thirty years later."]}),"\n",(0,i.jsx)(n.p,{children:"And the bill has arrived."}),"\n",(0,i.jsx)(n.p,{children:'Back to the opening. The champagne at that mobile game studio in Shanghai is still bubbling. The error messages in that R&D building in Shenzhen are still ticking. The distance between these two scenes\u2014from the prosperity of the application layer to the fracture at the foundation\u2014is not geographical. It is the accumulation of countless choices made by a nation over thirty years between "applications" and "foundations."'}),"\n",(0,i.jsx)(n.p,{children:"Every choice was rational. Every spreadsheet looked fantastic."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"But all those rational choices added together equal a bill that history never discounts."})}),"\n",(0,i.jsx)(n.p,{children:"This sentence sounds familiar. Because in Chapter 5 of the main text, when discussing Intel's cancellation of the Larrabee GPU project, the exact same sentence was used\u2014"}),"\n",(0,i.jsx)(n.p,{children:'"Nobody made a bad decision. Everyone made the most rational decision for their specific position. But all those rational decisions added up to a suicidal outcome."'}),"\n",(0,i.jsx)(n.p,{children:"Intel's version applied to a company. China's version applies to the industrial structure of an entire nation."}),"\n",(0,i.jsx)(n.p,{children:"The scale is different. The logic is exactly the same."})]})}function d(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>o,x:()=>r});var i=t(6540);const s={},a=i.createContext(s);function o(e){const n=i.useContext(a);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:o(e.components),i.createElement(a.Provider,{value:n},e.children)}}}]);